INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (2, '埃及总统塞西接见国家足球队', 14.029, 118, 63, '2026-07-08 00:46:01', '2026-07-14 19:38:10', '2026-07-08 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.577, 0.225, 0.198, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '但埃及球员疯狂抗议：在阿根廷发动这次反击之前，萨拉赫在另一端被犯规倒地，裁判没有吹停比赛，球权直接到了阿根廷脚下。以下是埃及队的犯规获利时间表：00：25埃及球员被断球后撞恩佐膝盖，裁判没有表示（危险动作）2：28麦卡利斯特无球状态下遭埃及球员冲撞2：29梅西持球遭埃及防守球员拉拽2：33梅西传球在埃及球员推搡干扰下传出界外5：47埃及防守球员发力推德保罗22：18埃及防守球员发力推梅西26：41埃及防守球员推搡恩佐34：54埃及防守球员用力推搡小蜘蛛35：51埃及防守球员用力推搡帕雷德斯36：15德保罗弧顶处无球状态下被埃及防守球员撕扯衣服倒地36：44埃及球员冲撞帕雷德斯致其倒地36：45梅西背身遭埃及防守球员冲撞推搡导致丢失球权，裁判没有任何表示41：40埃及球员无球状态下禁区内推搡阿尔瓦雷斯42：06埃及防守球员在弧顶处分别推搡恩佐和梅西49：26防守球员背身冲撞梅西46：48梅西带球推进遭埃及防守球员拉拽46：52麦卡利斯特背身做球被埃及防守球员拉倒54：30恩佐背身护球遭到埃及防守球员拉拽61：47麦卡利斯特被推倒埃及顺势打反击 裁判没有表示63：13麦卡利斯特向前带球推进被身后拉拽63：30萨拉赫对利马犯规阿根廷进攻有利被吹64：22梅西追球遭背后埃及防守球员拉拽74：25埃及队门将故意拖延时间不开球79：56梅西寻求撞墙，埃及防守球员抬臂阻挡梅西81：42埃及防守球员被梅西突破后伸手拉拽85：24埃及防守球员背后发力推恩佐88：01小蜘蛛持球后埃及防守球员上前拉拽99：37恩佐护球埃及防守球员拉拽且恶意冲撞恩佐100：20劳马护球埃及防守球员搂抱且另一名埃及队员主动挑衅。我是熬夜全程比赛看完的我认为裁判是没有问题的只是比较偏向南美风格，比较纵容对抗而且我认为其实也没太纵容在双方正常进行比赛当中，有些小犯规裁判不吹，保证球赛正常进行保证比赛观赏度本来就是正常的比如有一个阿根廷队员手打埃及球员脸的截图那个时候球在埃及球员，人家在进攻啊，你这个时候吹强行打断埃及进攻节奏。', '埃及、瑞士、塞西', '🔻阿根廷这人手上这么不干净。', '["萨拉", "科里纳", "斯卡", "洛尼", "恩佐"]', '{"credibility_score": 0.416, "official_ratio": 0.271, "verified_ratio": 0.669, "plain_user_ratio": 0.331, "verification_dist": {"普通用户": 0.331, "认证个人": 0.28, "官方平台": 0.271, "认证机构": 0.068, "头部认证个人": 0.051}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "新华社", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-08T02:12:57", "influence": 3165.3, "title": "#阿根廷队让二追三#【梅西传射创纪录 阿根廷绝地逆转埃及进世界杯八强】#阿根廷绝"}, {"role": "首次大V发声", "author": "直播吧", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T02:14:19", "influence": 3959.9, "title": "埃及全队投诉，阿根廷进球前，萨拉赫在阿根廷禁区倒地，埃及工作人员被红牌罚下。主帅"}, {"role": "初始爆料", "author": "雷速体育", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-08T02:53:31", "influence": 0.3, "title": "如何评价？微博热搜前二： 裁判偏心、阿根廷脏 - 知乎"}, {"role": "传播高峰", "author": "咪咕体育", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T13:22:41", "influence": 21215.2, "title": "#FIFA认定阿根廷进球判罚正确##FIFA认定埃及进球被取消判罚正确# 对于阿"}], "top_influencers": [{"author": "咪咕体育", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T13:22:41", "influence": 21215.2, "repost_count": 1606, "like_count": 57839, "comment_count": 4515, "title": "#FIFA认定阿根廷进球判罚正确##FIFA认定埃及进球被取消判罚正确# 对于阿"}, {"author": "马克欣", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-08T03:12:36", "influence": 12922.5, "repost_count": 496, "like_count": 38750, "comment_count": 1603, "title": "#阿根廷3比2埃及##阿根廷惊天逆转# 说实话，这些标题，都不如#阿根廷 脏#带"}, {"author": "头条新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T07:30:00", "influence": 11127.3, "repost_count": 443, "like_count": 31371, "comment_count": 2546, "title": "【#埃及足协向FIFA申诉#，要求全面调查勒泰西耶的严重误判】#阿根廷埃及主裁判"}, {"author": "评述员詹俊", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-08T02:41:41", "influence": 7730.5, "repost_count": 301, "like_count": 22100, "comment_count": 1599, "title": "#阿根廷绝杀埃及##阿根廷3比2埃及# 惊天大逆转，阿根廷队绝境逃生。埃及队的进"}, {"author": "梨视频", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T06:02:53", "influence": 5695.9, "repost_count": 182, "like_count": 15858, "comment_count": 1513, "title": "【#埃及队抗议#】阿根廷3比2埃及绝地逆转晋级。赛后，埃及主教练哈桑接受采访。“"}], "platform_chain": {"nodes": [{"name": "微博", "count": 46, "first_seen": "2026-07-08T00:46:01"}, {"name": "知乎", "count": 41, "first_seen": "2026-07-08T02:53:31"}, {"name": "澎湃新闻", "count": 4, "first_seen": "2