INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (4, '阿根廷以（转换）进攻为导向的逼抢', 12.248, 93, 63, '2026-06-22 15:55:41', '2026-07-14 21:10:05', '2026-07-11 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.302, 0.372, 0.326, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '从两球落后，到比赛临近结束时的连入三球逆转，阿根廷队上演了美加墨世界杯开赛至今，最为跌宕起伏的一场大戏。新华社记者 程敏 摄 连场进球 梅西在阿根廷队3:2逆转战胜埃及队的比赛中打进一球，将自己保持的世界杯连续进球场次扩大到9场。与瑞士队正面交锋，阿根廷队依然是更被看好过关的热门，但经历了前两场比赛的跌跌撞撞，蓝白军团的状态多少难以让人放心。', '埃及、瑞士、美加墨', '从妈宝男到节拍器，折腾自己10年的拉比奥，浪子回头_运动家_澎湃新闻-The Paper。', '["斯卡", "洛尼", "罗梅罗", "梅里", "阿尔瓦雷"]', '{"credibility_score": 0.58, "official_ratio": 0.581, "verified_ratio": 0.688, "plain_user_ratio": 0.312, "verification_dist": {"官方平台": 0.581, "普通用户": 0.312, "认证个人": 0.054, "头部认证个人": 0.032, "认证机构": 0.022}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-22T15:55:41", "influence": 0.0, "title": "世界杯播报丨姆巴佩将迎国家队里程碑 梅西能否创造新历史--文旅·体育--人民网"}, {"role": "首次大V发声", "author": "参考消息", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-28T12:49:57", "influence": 2662.9, "title": "【外媒：#伊朗队队长怒斥国际足联#】据西班牙《先锋报》网站6月27日报道，在美加"}, {"role": "初始爆料", "author": "老司机讲鬼故事", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-06-28T18:02:12", "influence": 3.4, "title": "要看你怎么定义假球了阿尔及利亚和奥地利的那场比赛，从70分钟开始，到伤停补时，这"}, {"role": "传播高峰", "author": "咪咕足球", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-04T08:44:49", "influence": 11619.5, "title": "#阿根廷16强# 2026世界杯1/16决赛，卫冕冠军阿根廷3-2力克佛得角，晋"}], "top_influencers": [{"author": "咪咕足球", "platform": "微博", "verification_type": "认证机构