INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (5, '在线分析！阿根廷和埃及这场球有没有吹黑哨？', 11.389, 31, 11, '2026-07-08 08:08:17', '2026-07-14 20:45:03', '2026-07-14 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.477, 0.269, 0.254, '["微博", "新浪新闻", "知乎"]', '主裁判先判阿根廷球员犯规，VAR回看后改判恩博洛假摔，给他黄牌。或者在尺度统一的情况下，裁判容忍阿根廷也容忍瑞士，恩波洛不该吃到第一张黄牌，也就没有后面的事情了。恩波洛有点搞笑的假摔，找的是这张被欠了30分钟的黄牌，如果主裁判给了牌，只是相当于帕雷德斯晚了30分钟吃黄，整体阿根廷小赚，但是大体把尺度拉回来一些。', '瑞士、埃及、美加墨', '当年悄悄收钱，却被球迷公认金哨的陆俊说过，黑哨不会在关键上下手脚，相反手段非常隐蔽。', '["恩博洛", "帕雷德", "奥莱", "高清", "陆俊"]', '{"credibility_score": 0.434, "official_ratio": 0.29, "verified_ratio": 0.677, "plain_user_ratio": 0.323, "verification_dist": {"普通用户": 0.323, "官方平台": 0.29, "认证个人": 0.226, "头部认证个人": 0.161}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "Herry", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-08T08:08:17.000001", "influence": 1073.6, "title": "当年悄悄收钱，却被球迷公认金哨的陆俊说过，黑哨不会在关键上下手脚，相反手段非常隐"}, {"role": "首次大V发声", "author": "2中1", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-12T13:06:25.999999", "influence": 445.5, "title": "恩博洛吃第二张黄牌有点冤，这次身体对抗很轻微，他只是没站稳倒地，没想骗犯规。 主"}, {"role": "首次官方媒体介入", "author": "夜白侃球", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-12T15:42:55", "influence": 0.0, "title": "“保送阿根廷”舆论再起！争议红牌助力阿根廷淘汰瑞士挺进世界杯四强"}], "top_influencers": [{"author": "Herry", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-08T08:08:17.000001", "influence": 1073.6, "repost_count": 0, "like_count": 2947, "comment_count": 379, "title": "当年悄悄收钱，却被球迷公认金哨的陆俊说过，黑哨不会在关键上下手脚，相反手段非常隐"}, {"author": "2中1", "platform": "微博", "verification_type": "头部认证个人", "pu