INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (11, '沈阳暴雨辽宁：今天雨量升级 多地有暴雨大暴雨！', 13.44, 91, 100, '2026-06-04 16:50:38', '2026-07-14 20:56:57', '2026-07-14 12:00:00', 'mid', 'growth', 0.9, 0.05, 0.9, 0.05, 0.0, '当前事件报道数量持续增加，公众关注度快速提升，处于成长期。', 0.498, 0.382, 0.12, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '记者从水利部了解到，受台风“美莎克”影响，7月5日至7日，西江、柳江、桂江、郁江、桂南沿海诸河等主要河流将出现明显涨水过程，其中西江干流及支流柳江桂江可能发生超警洪水，暴雨区内部分中小河流可能发生较大洪水。前期，广西大部降雨强度大、时间长，具有极端性，桂东和沿海地区7日晚到9日降水持续，局地强度大，发生山洪地质灾害、城市暴雨积涝和中小河流洪水的气象风险高，在开展涉险水库抢险救援的同时，需谨防出现新的灾害。自治区水文中心预测，未来12小时，都柳江三江侗族自治县洋溪乡河段将复涨，并再次出现超警戒水位3.5米左右洪水，柳江柳州市城区河段将出现83.2米左右的洪峰水位。', '广西、南宁、贵港', '广西洪水漂浮1.6万死猪已捞500头，官方称不会流上餐桌_绿政公署_澎湃新闻-The Paper。', '["美莎克", "雷雨", "黄淮", "杨驰", "覃塘区"]', '{"credibility_score": 0.795, "official_ratio": 0.879, "verified_ratio": 0.967, "plain_user_ratio": 0.033, "verification_dist": {"官方平台": 0.879, "认证机构": 0.077, "普通用户": 0.033, "认证个人": 0.011}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网－广西频道", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-04T16:50:38", "influence": 0.0, "title": "贵港供电局全力筑牢高考保电安全防线"}, {"role": "初始爆料", "author": "胡飞飞", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-06T15:43:34", "influence": 0.3, "title": "广西郁江发生2026年第1号洪水，贵港水文站水位超警戒1.80米 - 知乎"}, {"role": "传播高峰", "author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-06T18:33:26", "influence": 7821.7, "title": "#广西洪水##安排1亿元支持广西灾后恢复#【 #广西2地洪水防御应急响应升为一级"}, {"role": "首次大V发声", "author": "大皖新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-14T06:43:51", "influence": 130.8, "title": "【中央气象台发布暴雨橙色预警 辽宁、广西等地部分地区有大暴雨】14日6时，中央气"}], "top_i