INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (12, '多地摩友自发驰援广西将物资送入村', 11.65, 54, 9, '2026-06-20 09:26:26', '2026-07-14 20:03:00', '2026-07-13 12:00:00', 'mid', 'peak', 0.9, 0.0, 0.05, 0.9, 0.05, '当前事件报道量已接近峰值，关注度趋于稳定，处于高潮期。', 0.783, 0.196, 0.022, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '爷爷不泡茶首批物资已送达 ·霸王茶姬紧急驰援广西防汛救灾 ·北京星巴克公益基金会捐款100万元 ·百胜中国携旗下多品牌捐赠300万元驰援灾区 ·驰援广西洪涝灾区，海底捞捐赠首批3万份自热火锅 农牧养殖 ·牧原公益基金会向广西受灾地区捐赠现金2000万元 食品饮料 ·卫龙美味向广西洪涝灾区捐赠100万元，助力防汛救灾与产业重建 ·蒙牛紧急驰援广西南宁洪涝灾区 ·伊利集团第一时间驰援广西南宁受灾群众 ·农夫山泉捐赠现金1000万元，调拨应急饮用水驰援广西 ·东鹏饮料捐款1000万元及10万瓶饮料驰援广西 互联网平台 ·腾讯公益慈善基金会启动2000万元备灾资金，驰援广西等地灾情 ·小米公益基金会捐赠1000万元现金，紧急驰援广西等地救灾 ·拼多多紧急捐赠1000万元，驰援广西防汛救灾 ·持续跟进。阿里巴巴驰援广西三批物资已经抵达 ·网易捐赠首批25000份物资支援救灾 ·20万份物资陆续送达，美团驰援广西受灾地区 ·京东物流捐赠生活急需物资，送往广西南宁洪涝灾区 汽车制造 ·比亚迪慈善基金会捐赠1000万元驰援广西灾区 纺织服饰 ·安踏集团携手中华慈善总会捐赠1000万元物资 紧急驰援广西救灾 ·李宁集团捐赠2000万元物资驰援救灾一线 ·特步集团紧急捐赠1000万元物资驰援广西、湖北、甘肃等受灾地区 ·361°集团携手中华慈善总会捐赠1000万元物资全力支援广西救灾 ·鸿星尔克携手中华社会救助基金会捐赠800万元物资驰援广西受灾地区 ·匹克集团携手中华慈善总会捐赠500万元物资全力驰援抗洪救灾一线 ·波司登紧急捐赠1000万元物资全力支援广西抗洪救灾一线 ·罗莱生活捐赠200万元物资驰援广西防汛救灾 潮玩文创 ·泡泡玛特捐赠1000万元人民币，驰援救灾一线 一、连锁餐饮 蜜雪冰城向广西受灾地区捐赠1000万元，支援防汛救灾和产业恢复 喜茶再次捐赠200万元驰援广西防汛救灾 7月7日，喜茶宣布驰援广西防汛救灾，灾情发生后，喜茶联合中国乡村发展基金会开展灾区救援及物资援助。三、食品饮料 卫龙美味向广西洪涝灾区捐赠100万元，助力防汛救灾与产业重建 蒙牛紧急驰援广西南宁洪涝灾区 蒙牛集团第一时间启动应急响应机制，安排向广西南宁洪涝灾区捐赠牛奶等营养物资。', '广西、贵港、台风', '洪水无情工会有爱。', '["美莎克", "张雪", "覃塘区", "刘宇宁", "余波"]', '{"credibility_score": 0.838, "official_ratio": 0.685, "verified_ratio": 0.981, "plain_user_ratio": 0.019, "verification_dist": {"官方平台": 0.685, "认证机构": 0.204, "认证个人": 0.056, "头部认证个人": 0.037, "普通用户": 0.019}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "青海日报", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-20T09:26:26", "influence": 0.0, "title": "海东76吨果蔬运往地震灾区"},