INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (15, '国产动力舟桥救援广西学子脱险', 7.682, 49, 23, '2026-07-09 09:33:00', '2026-07-14 13:22:27', '2026-07-12 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.634, 0.366, 0.0, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '广西被困40小时学生讲述被救经历：感谢救援队不放弃任何人，多年后会记得我是坐船离开学校的 7月6日晚，位于广西贵港的广西物流职业技术学院因洪水涌入，宿舍楼一楼被完全淹没，近8000名师生被困，一度断粮断水。广西洪水救援队冲破阻隔抵达，师生见证众志成城 当救援力量抵达，冲破洪水的阻隔，那一刻，所有学子师生的眼睛都亮了。广西贵港特大洪水致6000学生被困，动力舟桥成功转移 #广西洪水#广西贵港遭遇特大洪水，一学校6000名学生被困，“救援界航母”动力舟桥紧急出动，成功转移所有的被困学生。', '广西、贵港、舟桥', '#动力舟桥转移数千名被困学生#】急流阻断道路怎么办。', '["美莎克", "高中生", "廖小华"]', '{"credibility_score": 0.768, "official_ratio": 0.673, "verified_ratio": 0.959, "plain_user_ratio": 0.041, "verification_dist": {"官方平台": 0.673, "认证机构": 0.163, "认证个人": 0.061, "头部认证个人": 0.061, "普通用户": 0.041}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T09:33:00", "influence": 1817.4, "title": "【硬核救援！#动力舟桥转移数千名被困学生#】急流阻断道路怎么办？“救援航母”——"}, {"role": "首次大V发声", "author": "中国新闻网", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T13:39:14", "influence": 21331.9, "title": "【#广西洪灾救援无人机变有人机#】#原则上无人机不许吊人但人民大于原则#广西洪灾"}, {"role": "初始爆料", "author": "LECOME乐康优品", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-10T10:06:16", "influence": 0.3, "title": "贵港1.2万师生被困“孤岛”，解放军冲锋舟劈开洪水：灾难面前的“中国速度”是怎么"}], "top_influencers": [{"author": "中国新闻网", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T13:39:14", "influence": 21331.9, "repost_count": 2883, "like_count": 58418, "comment_count": 1847, "title": "【#广西洪灾救援无人机变有人机#】#原则上无人机不许吊人但人民大于原则#广西洪灾"}, {"author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T18:00:00", "influence": 9989.2, "repost_count": 1916, "like_count": 24739, "comment_count": 1303, "title": "【硬核救援！#救援航母出现那一刻安全感拉满#】#救援航母上响起歌唱祖国# 近日，"}, {"author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T10:21:12", "influence": 9906.9, "repost_count": 1311, "like_count": 26883, "comment_count": 1062, "title": "【#当救援航母驶入洪水校园#[心]】#动力舟桥洪水中化身生命方舟# 近日，广西贵"}, {"author": "绿茶发言大赏", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-10T20:03:27", "influence": 6381.2, "repost_count": 581, "like_count": 18819, "comment_count": 309, "title": "感觉这张照片可以上《感动中国》了[苦涩] 广西贵港洪灾区蓝天救援队在转移贵港高中"}, {"author": "中国新闻网", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T19:09:13", "influence": 6346.1, "repost_count": 907, "like_count": 16407, "comment_count": 1034, "title": "【致敬！#贵港救援人员席地而坐冒雨吃饭#】广西贵港一线救援人员席地而坐，在雨中休"}], "platform_chain": {"nodes": [{"name": "微博", "count": 18, "first_seen": "2026-07-09T09:33:00"}, {"name": "澎湃新闻", "count": 5, "first_seen": "2026-07-09T10:25:00"}, {"name": "人民网", "count": 5, "first_seen": "2026-07-09T17:56:24"}, {"name": "知乎", "count": 3, "first_seen": "2026-07-10T10:06:16"}, {"name": "新浪新闻", "count": 18, "first_seen": "2026-07-10T14:24:41.000001"}], "links": [{"source": "微博", "target": "澎湃新闻", "value": 5}, {"source": "澎湃新闻", "target": "人民网", "value": 5}, {"source": "人民网", "target": "知乎", "value": 3}, {"source": "知乎", "target": "新浪新闻", "value": 18}]}}', '2026-07-15 12:30:32', '2026-07-15 12:30:32');
