INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (18, '广西暴雨超8000人抗洪救援', 5.917, 34, 16, '2026-07-07 23:30:38', '2026-07-14 20:56:17', '2026-07-11 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.526, 0.368, 0.105, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '在洪水灾害面前，救人的从来不是一架无人机，而是一整套正在成型的国家低空基础设施。五年，无人机从工具长成了基础设施▲ 五年四场洪水，无人机从"工具"一路长成"基础设施"（配图提示词见《配图提示词_ChatGPT出图_v9》图1）看到了吗——每过一场洪水，无人机头顶上要扛的活，就多叠一层。而从2021年的郑州，到2026年的广西，这五年、四场洪水，真正被改写的，从来不是"我们有多少架无人机"，而是——一个国家，组织和调动低空力量的方式。', '广西、横州、大疆', '洪水过境贵港故土：见过无常，才懂平安是此生最大的福报 - 知乎。', '["美莎克", "陆军", "黄银贵"]', '{"credibility_score": 0.525, "official_ratio": 0.5, "verified_ratio": 0.588, "plain_user_ratio": 0.412, "verification_dist": {"官方平台": 0.5, "普通用户": 0.412, "认证个人": 0.059, "认证机构": 0.029}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "渡川见心", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-07T23:30:38.000001", "influence": 0.0, "title": "洪水过境贵港故土：见过无常，才懂平安是此生最大的福报 - 知乎"}, {"role": "首次官方媒体介入", "author": "爆闻速递小哥", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-10T07:36:46", "influence": 0.0, "title": "广西暴雨超8000人抗洪救援"}, {"role": "传播高峰", "author": "大又元", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-11T09:12:10", "influence": 385.0, "title": "命运反复出题，而你给出的答案一次比一次震撼！这个构图绝了，原则上无人机不能载人，"}, {"role": "首次大V发声", "author": "JSTV荔枝视频", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-13T21:12:38", "influence": 0.0, "title": "【#10位村民头顶雨布被困洪水5天4晚##真实记录广西灾区的1场极限救援#】被困"}], "top_influencers": [{"author": "大又元", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-11T09:12:10", "i