INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (19, '广西洪水退去武警清淤遇暖心一幕', 5.86, 29, 13, '2026-07-09 09:56:00', '2026-07-14 20:13:47', '2026-07-12 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 1.0, 0.0, 0.0, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '在受灾严重的广西南宁横州市、贵港市，张国清来到受灾群众安置点、居民小区、临街店铺和六蓝村、独田村，转达习近平总书记对灾区广大干部群众的关怀慰问和深情牵挂，实地察看集中安置群众生活条件，详细了解道路清淤、环境消杀、供水供电供气及受灾群众生活保障等情况。很多偏远山村道路塌方、车辆无法通行，救援人员便徒步穿梭在泥泞山路，背着物资、带着装备，翻山越岭奔赴孤岛村落，为被困群众送去饮用水、食物和应急物资，保障群众基本生活所需。在全力抢险救援、转移安置群众的同时，各项灾后安置、民生保障工作同步高效推进，最大程度守护群众生命安全、保障群众基本生活。', '广西、横州、台风', '广西疾控：暴雨灾区传染病疫情总体平稳，需重点防范五类疾病_直击现场_澎湃新闻-The Paper。', '["美莎克", "张国清", "陆军", "覃塘区", "汤圆"]', '{"credibility_score": 0.821, "official_ratio": 0.862, "verified_ratio": 0.931, "plain_user_ratio": 0.069, "verification_dist": {"官方平台": 0.862, "普通用户": 0.069, "认证个人": 0.034, "认证机构": 0.034}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "澎湃新闻", "platform": "澎湃新闻", "verification_type": "官方平台", "publish_time": "2026-07-09T09:56:00", "influence": 0.0, "title": "广西疾控：暴雨灾区传染病疫情总体平稳，需重点防范五类疾病_直击现场_澎湃新闻-T"}, {"role": "初始爆料", "author": "山巅晨阳", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-11T08:53:37", "influence": 0.0, "title": "广西汛情趋缓，但子弟兵仍在泥泞中抢通最后一公里 - 知乎"}, {"role": "传播高峰", "author": "人民日报", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-11T21:46:18", "influence": 3684.1, "title": "#这就是人民子弟兵给的安全感#【#清淤现场村民朝子弟兵竖起大拇指#】连日来，广西"}, {"role": "首次大V发声", "author": "央视军事报道", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-13T20:55:54", "influence": 0.8, "title": "#抢险救援 子弟兵在行动#经过几天的救援，广西横州洪水逐步减退。今天，解放军和武"}], "top_influencers": [{"auth