INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (22, '上蹿下跳半年，金价继续“猴”？', 16.205, 156, 101, '2026-06-01 09:05:01', '2026-07-14 20:58:00', '2026-07-13 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.415, 0.361, 0.224, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '” FxPro高级市场分析师Alex Kuptsikevich预计下周黄金价格将继续下跌，“美伊谅解备忘录签署引发的金价上涨似乎已在美联储鹰派立场下结束，并引发了一波美元买盘。这意味着压制金价的“加息定价”很可能已经过度——若美伊协议推动地缘风险缓和、油价回落带动通胀预期降温，市场对美联储鹰派路径的定价可能逐步修正，进而带动实际利率与美元走弱，为黄金打开上行空间。同时，近期公布的美国宏观经济数据整体表现积极，叠加新任美联储主席‘通过缩表重塑市场对美元信心及长期通胀可控预期’的政策主张，美元走强亦对黄金价格形成部分压力。', '美国、东京、中东', '最精明的资产选择。', '["白银", "特朗普", "高盛", "金改", "刘春燕"]', '{"credibility_score": 0.669, "official_ratio": 0.686, "verified_ratio": 0.801, "plain_user_ratio": 0.199, "verification_dist": {"官方平台": 0.686, "普通用户": 0.199, "认证个人": 0.064, "认证机构": 0.032, "头部认证个人": 0.019}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "证券日报", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-01T09:05:01", "influence": 0.0, "title": "金价5月份“过山车”后去向何方？--经济·科技--人民网"}, {"role": "初始爆料", "author": "三相三悟", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-06-20T11:26:13", "influence": 0.3, "title": "美联储加息周期对黄金价格、实物金饰的完整传导逻辑 - 知乎"}, {"role": "首次大V发声", "author": "红星新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T08:06:20", "influence": 60.4, "title": "【#一觉醒来黄金又跌了#】#黄金又跌破4100美元了# 北京时间7月8日，国际油"}, {"role": "传播高峰", "author": "三联生活周刊", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-10T12:52:51", "influence": 82.0, "title": "#金价暴跌普通人现在还能抄底买金吗# 最近，国际黄金价格一度跌破4000美元/盎"}], "top_influencers": [{"author": "三联生活周刊", "platform": "微