INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (24, '油价下跌原因国际油价又跌了', 10.474, 36, 12, '2026-06-09 09:36:33', '2026-07-14 21:12:45', '2026-07-13 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.759, 0.172, 0.069, '["人民网", "微博", "新浪新闻", "知乎"]', '国际评级机构惠誉维持2026年布伦特原油全年87美元/桶的均价基准，不过，该机构将今年四季度油价预期下调到70美元/桶至73美元/桶，前提是伊朗原油出口持续放量、石油输出国组织（欧佩克）与非欧佩克产油国组成的“欧佩克+”灵活释放闲置产能。【#国际油价又飙升# #金银再度急跌#】财联社7月8日电，布伦特原油期货涨幅扩大至4%，报77.155美元/桶。美伊冲突持续 国际油价涨超3% 【美伊冲突持续 国际油价涨超3%】由于美国与伊朗军事冲突持续引发国际市场对原油供应的担忧，国际原油期货价格12号在新一周交易开始后显著上涨，涨幅超3%。', '美伊、霍尔木兹海峡、伊朗', '其实我已经掌握了规律，油价涨了金价就跌了，金价涨了油价就跌了，开油车和买黄金的人已经不用再看这些新闻。', '["特朗普", "布伦特", "白银", "欧佩克"]', '{"credibility_score": 0.486, "official_ratio": 0.222, "verified_ratio": 0.806, "plain_user_ratio": 0.194, "verification_dist": {"认证个人": 0.25, "官方平台": 0.222, "普通用户": 0.194, "认证机构": 0.167, "头部认证个人": 0.167}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次大V发声", "author": "新浪财经", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-09T09:36:33", "influence": 80.3, "title": "#油价存在失控风险#【中金财富期货：目前黄金市场在流动性短缺和通胀压力的双重挤压"}, {"role": "首次官方媒体介入", "author": "经济日报", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-07-03T09:02:47", "influence": 0.0, "title": "国际油价仍未挣脱“海峡困局”--经济·科技--人民网"}, {"role": "初始爆料", "author": "木已断水", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-03T21:12:34", "influence": 1.5, "title": "之前大战爆发的时候，就已经分析了，石油下跌后的利好品种。再系统梳理下，利好品种内"}], "top_influencers": [{"author": "新浪财经", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-09T09:36:33", "influence": 80.3, "repost_count": 28, "like_count": 126, "comment_count": 29, "title": "#油价存在失控风险#【中金财富期货：目前黄金市场在流动性短缺和通胀压力的双重挤压"}, {"author": "但斌", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-06-15T09:14:33", "influence": 76.0, "repost_count": 12, "like_count": 210, "comment_count": 2, "title": "美伊达成和平协议，霍尔木兹海峡开放！国际油价直线大跌4%，黄金重回4300美元，"}, {"author": "秦永臣DXY", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-04T07:41:20", "influence": 62.8, "repost_count": 4, "like_count": 136, "comment_count": 36, "title": "不要豪赌油价 我之前在评论原油和黄金都下跌的情况下，买金还是买油的问题时，明确说"}, {"author": "游戏投投机", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-14T10:47:49", "influence": 55.7, "repost_count": 10, "like_count": 124, "comment_count": 17, "title": "#金价再度失守4000##金银急跌原油大涨# 油价又大涨，黄金承压断崖式回落，黄"}, {"author": "我不想买白酒", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-08T16:36:35", "influence": 47.1, "repost_count": 1, "like_count": 92, "comment_count": 37, "title": "股灾又要来了 美伊局势变动 又要开始做空全球了 特朗普称美伊谅解备忘录已终结 原"}], "platform_chain": {"nodes": [{"name": "微博", "count": 21, "first_seen": "2026-06-09T09:36:33"}, {"name": "人民网", "count": 1, "first_seen": "2026-07-03T09:02:47"}, {"name": "知乎", "count": 6, "first_seen": "2026-07-03T21:12:34"}, {"name": "新浪新闻", "count": 7, "first_seen": "2026-07-09T11:14:40"}], "links": [{"source": "微博", "target": "人民网", "value": 1}, {"source": "人民网", "target": "知乎", "value": 6}, {"source": "知乎", "target": "新浪新闻", "value": 7}]}}', '2026-07-15 12:30:32', '2026-07-15 12:30:32');
