INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (25, '黄金下周看涨，地缘摩擦与降息预期支撑金价', 8.274, 23, 1, '2026-07-12 17:33:02', '2026-07-14 21:16:12', '2026-07-12 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.5, 0.3, 0.2, '["微博", "新浪新闻"]', '7.13策略：周末五大重磅利好，明日五大主线开启A股纠错行情 大家周末好，这个周末国内政策核弹级轰炸。国际局势美伊冲突也开始有所缓和，国常会和商务部五大重磅利好齐发，明日周一A股怎么走。📊黄金周一开盘实操指南｜周末7.12全网消息梳理 + 4 条必备操作策略✨ 周五金价收盘4108美元守住60周牛熊线，周末两大核心因素锁定开盘基调： 1、中东冲突再起推升油价，通胀担忧加剧，CME 数据显示9月美联储加息概率升至69%，10 年期美债收益率高位震荡，持续压制黄金反弹空间。', '美国、美伊、中东', '7.13策略：周末五大重磅利好，明日五大主线开启A股纠错行情 大家周末好，这个周末国内政策核弹级轰炸。', '["周末好", "陈杰", "黄金周"]', '{"credibility_score": 0.386, "official_ratio": 0.043, "verified_ratio": 0.957, "plain_user_ratio": 0.043, "verification_dist": {"认证个人": 0.565, "头部认证个人": 0.348, "官方平台": 0.043, "普通用户": 0.043}, "factors": ["official_absent"]}', '{"key_nodes": [{"role": "首次大V发声", "author": "卧龙先生-驭龍", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-12T17:33:02", "influence": 3.0, "title": "7.13策略：周末五大重磅利好，明日五大主线开启A股纠错行情 大家周末好，这个周"}, {"role": "传播高峰", "author": "猎庄阿哲", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T22:28:01.999999", "influence": 157.2, "title": "周末突发海峡封锁！持仓有色的人，这下又要失眠了 周末刷到伊朗封锁霍尔木兹海峡的新"}, {"role": "首次官方媒体介入", "author": "smoothY蓝波", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-12T23:46:09.000001", "influence": 0.0, "title": "黄金下周看涨，地缘摩擦与降息预期支撑金价"}, {"role": "初始爆料", "author": "黄金风向标-老谭", "platform": "微博", "verification_type": "普通用户", "publish_time": "2026-07-13T20:24:06.000001", "influence": 0.3, "title": "明日将公布关键 CPI 通胀数据，周三美联储主席还会进行国会证词，会在数据落地后"}], "top_influencers": [{"author": "猎庄阿哲", "platform": "微博", "verification_type": "