INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (26, '国际油价13日大幅上涨', 7.867, 11, 0, '2026-07-13 18:11:20', '2026-07-14 22:19:45', '2026-07-14 12:00:00', 'mid', 'growth', 0.9, 0.05, 0.9, 0.05, 0.0, '当前事件报道数量持续增加，公众关注度快速提升，处于成长期。', 0.2, 0.6, 0.2, '["微博", "新浪新闻"]', '国信证券研报指出，2026年贵金属行业短期受美伊冲突推升油价、通胀预期回升及美国就业数据超预期导致美联储政策预期转向影响， 金价阶段性承压回落至4000—4200美元/盎司区间， 但中长期逻辑依然稳固，全球央行持续增持黄金 ， 2026年一季度购金量达243.7吨，中国央行已连续20个月增持黄金。国信证券研报指出，2026年贵金属行业短期受美伊冲突推升油价、通胀预期回升及美国就业数据超预期导致美联储政策预期转向影响，金价阶段性承压回落至4000—4200美元/盎司区间， 但中长期逻辑依然稳固，全球央行持续增持黄金 ，2026年一季度购金量达243.7吨，中国央行已连续20个月增持黄金。金价单日暴跌超20元每克，金价年内跌幅已近485元每克 【#金价单日暴跌超20元每克#，#金价年内跌幅已近485元每克#】7月14日，国内黄金零售市场延续跌势，周生生足金饰品报价为1214元/克，较前一日跌24元/克。', '伦敦、上海、霍尔木兹海峡', '油价由跌转涨 四连降恐泡汤。', '["周大福", "周生生", "布伦特"]', '{"credibility_score": 0.873, "official_ratio": 0.727, "verified_ratio": 0.909, "plain_user_ratio": 0.091, "verification_dist": {"官方平台": 0.727, "认证机构": 0.182, "普通用户": 0.091}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "小新正在场", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-13T18:11:20.000001", "influence": 0.0, "title": "油价由跌转涨 四连降恐泡汤"}, {"role": "首次大V发声", "author": "新浪新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-14T17:21:24", "influence": 99.2, "title": "【油价大涨！#金价又绷不住了#，#买50克三金半年便宜近2万元#！】7月14日早"}, {"role": "初始爆料", "author": "姚中国", "platform": "微博", "verification_type": "普通用户", "publish_time": "2026-07-14T21:27:52", "influence": 0.0, "title": "#共同关注##买50克三金半年便宜近2万元##金价又绷不住了# 2026年上半年"}], "top_influencers": [{"author": "新浪新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-14T17:21:24", "influence": 99.2, "repost_count": 67, "like_count": 94, "comment_count": 8, "title": "【油价大涨！#金价又绷不住了#，#买50克三金半年便宜近2万元#！】7月14日早"}], "platform_chain": {"nodes": [{"name": "新浪新闻", "count": 8, "first_seen": "2026-07-13T18:11:20.000001"}, {"name": "微博", "count": 3, "first_seen": "2026-07-14T17:21:24"}], "links": [{"source": "新浪新闻", "target": "微博", "value": 3}]}}', '2026-07-15 12:30:32', '2026-07-15 12:30:32');
