INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (27, '黄金生意难做 为什么大家都不买了呢？', 7.864, 65, 39, '2026-06-02 11:02:58', '2026-07-14 19:54:21', '2026-07-10 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.328, 0.414, 0.258, '["微博", "新浪新闻", "知乎"]', '给出 伦敦铝 黄金 伦敦锡 白银的近期规划（更快更详细的规划请参阅我们的每日更新的专栏文章的内容）：1】伦敦铝：6月27号：伦敦铝继续下跌，盘面很弱势，但这个位置不宜过度追空伦敦铝，一方面技术面的乖离过大，很容易反弹，另外原油本身也是被强行压制的，这取决于帝国自己的能力，但原油反弹的压力毕竟还是存在的。买了请拿稳仓位啊，这图看一遍，稍后我们A股那篇再详细讲：给出 黄金 伦敦铜 有色金属 白银的近期规划（更快更详细的规划请参阅我们的每日更新的专栏文章的内容）：1】黄金：7月3号：黄金如期走高，且盘面相对稳定，渐渐符合我们规划的达到“周K”的“小窗口”反弹波的规模，且量能不大。2）由于是“小反弹窗口”，涨幅是动态确定的，是需要整体股市盘面 Fed美联储 帝国的管理水平等很多因素来共同促成这个短期反弹的时长的，那么之前规划并强调了黄金的小仓位参加，白银的态度则相对不重要，3天前对白银的态度更佳明确，但没参加到此刻也请不要重仓参与，轻仓快速才适合当下的行情，你不能期盼你能吃到每一个涨跌波段，快速击败股神。', '美伊、美国、伦敦', '油小跌，气小涨，黄金白银震荡，其它基本都是震荡。', '["布伦特", "耶耶", "黄金周", "孙子", "秦钰恒"]', '{"credibility_score": 0.168, "official_ratio": 0.031, "verified_ratio": 0.292, "plain_user_ratio": 0.708, "verification_dist": {"普通用户": 0.708, "认证个人": 0.215, "头部认证个人": 0.046, "官方平台": 0.031}, "factors": ["official_absent", "mostly_unverified", "high_duplicate_rate"]}', '{"key_nodes": [{"role": "初始爆料", "author": "alex01", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-02T16:20:11", "influence": 42.2, "title": "先说加息，昨天的Fed美联储主席的话说明：Fed美联储距离端出大动作还早得很，因"}, {"role": "首次大V发声", "author": "金浪逐峰", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-04T22:51:56", "influence": 9.6, "title": "非农爆冷迎地缘大考，黄金周一怎么走？ 本周宏观日程罕见错位，美国6月非农提前至7"}, {"role": "传播高峰", "author": "TopView", "platform": "知乎", "verification_type": "头部认证个人", "publish_time": "2026-07-09T22:13:04", "influence": 174.2, "title": "2026年7月8日，伦敦金现收在4047美元。今年1月29号，它最高摸到过558"}, {"role": "首次官方媒体介入", "author": "星辰失控者", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-14T01:23:39", "influence": 0.0, "title": "黄金生意难做 为什么大家都不买了呢？"}], "top_influencers": [{"author": "TopView", "platform": "知乎", "verification_type": "头部认证个人", "publish_time": "2026-07-09T22:13:04", "influence": 174.2, "repost_count": 0, "like_count": 474, "comment_count": 64, "title": "2026年7月8日，伦敦金现收在4047美元。今年1月29号，它最高摸到过558"}, {"author": "环中星鉴", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-03T13:32:08", "influence": 138.7, "repost_count": 0, "like_count": 354, "comment_count": 65, "title": "我一直在监测的几个构成黄金反弹的条件，昨天全都激活了，所以昨天的文章已经预告过，"}, {"author": "派大星皮皮", "platform": "知乎", "verification_type": "认证个人", "publish_time": "2026-07-03T17:32:15", "influence": 122.2, "repost_count": 0, "like_count": 214, "comment_count": 116, "title": "涨了看涨、跌了看跌，两头都有理由？那独立思考的意义又如何体现！关于加息以及对黄金"}, {"author": "heIp", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-10T17:32:31", "influence": 98.4, "repost_count": 38, "like_count": 183, "comment_count": 11, "title": "最近金价回落，网上有一个很火的说法： 黄金的涨跌，根本就不是为了让你发财的。 普"}, {"author": "秦钰恒", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-06-02T11:02:58", "influence": 76.1, "repost_count": 2, "like_count": 102, "comment_count": 87, "title": "发布了头条文章：《秦钰恒：黄金陷入“谈谈打打”困局！4460-4520震荡磨底》"}], "platform_chain": {"nodes": [{"name": "微博", "count": 11, "first_seen": "2026-06-02T11:02:58"}, {"name": "知乎", "count": 51, "first_seen": "2026-07-02T16:20:11"}, {"name": "新浪新闻", "count": 2, "first_seen": "2026-07-14T01:23:39"}], "links": [{"source": "微博", "target": "知乎", "value": 51}, {"source": "知乎", "target": "新浪新闻", "value": 2}]}}', '2026-07-15 12:30:32', '2026-07-15 12:30:32');
