INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (28, '现货黄金失守4000美元，国内金饰单日跌超20元', 6.094, 8, 0, '2026-07-14 17:32:14', '2026-07-14 21:45:12', '2026-07-14 12:00:00', 'mid', 'peak', 0.6, 0.0, 0.2, 0.6, 0.2, '当前事件报道量已接近峰值，关注度趋于稳定，处于高潮期。', 0.295, 0.462, 0.244, '["微博", "新浪新闻"]', '现货黄金失守4000美元，国内金饰单日跌超20元。本文基于以下微博话题的智搜结果生成 现货黄金7月14日再度失守4000美元/盎司，国内品牌足金饰品单日下跌20-24元，老凤祥、周生生等克价已从年初1700元以上的高位累计跌超500元。二、为什么原料金价“8字头”，金饰还在“12字头” 定价结构差异：品牌金饰价格＝原料金价＋品牌溢价＋工艺费＋渠道成本，品牌溢价通常在300-400元/克。', '美伊、上海', '#金饰价格又崩了#。', '["沃勒"]', '{"credibility_score": 0.462, "official_ratio": 0.125, "verified_ratio": 1.0, "plain_user_ratio": 0.0, "verification_dist": {"认证个人": 0.5, "头部认证个人": 0.375, "官方平台": 0.125}, "factors": []}', '{"key_nodes": [{"role": "初始爆料", "author": "毒舌数码", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-14T17:32:14", "influence": 145.8, "title": "#金饰价格又崩了#？？？1200多叫崩吗。这样不痛不痒的降一点刺激不了消费，我说"}, {"role": "首次大V发声", "author": "暖宝宝宝宝宝宝_", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-14T17:58:48", "influence": 8.8, "title": "#金饰价格又崩了#好几天没打开看金价了[泪奔]"}, {"role": "首次官方媒体介入", "author": "赛博AI实验室", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-14T18:14:07", "influence": 0.0, "title": "现货黄金失守4000美元，国内金饰单日跌超20元"}], "top_influencers": [{"author": "毒舌数码", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-14T17:32:14", "influence": 145.8, "repost_count": 7, "like_count": 391, "comment_count": 43, "title": "#金饰价格又崩了#？？？1200多叫崩吗。这样不痛不痒的降一点刺激不了消费，我说"}, {"author": "清纯痣", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-14T17:43:57.000001", "influence": 50.3, "repost_count": 6, "like_count": 111, "comment_count": 